  coaching_execution = '{"movement_description":"Handstand or near-handstand entry with fast hollow snap-down to feet together.","setup":["Mat required.","Use wall, wedge, or handstand snap-down setup.","Athlete must understand hollow shape.","Coach controls intensity."],"execution_steps":["Enter handstand or near-handstand shape.","Keep arms straight.","Push through shoulders.","Snap legs down together.","Land feet together.","Finish arms up and body tight."],"coach_cues":["Push tall.","Tight hollow.","Feet together.","Snap down fast.","Rebound shape, not squat landing."],"athlete_cues":["Snap feet.","Squeeze legs.","Arms up.","Land tight."],"common_faults":["Slow snap-down.","Bent arms.","Feet landing apart.","Piking down.","Dead landing with no body tension.","Shoulders collapsing."],"stop_signs":["Wrist/shoulder pain.","Hard uncontrolled landing.","Knee collapse.","Athlete lacks cartwheel/handstand prerequisite.","Fear or loss of orientation."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Round-off entry work","Hurdle Step to Lunge Shape","Rebound mechanics"],"pairs_well_after":["Cartwheel Finish Lunge","Handstand Line","Hollow Body Hold","Wall Body-Line Drill"],"good_for_sessions":["tumbling_prep","landing_prep","general_warmup"],"avoid_before":["High-output tumbling if snap-down is slow or unsafe","Back handspring connections if rebound position is poor"],"avoid_after":[],"do_not_use_when":["No cartwheel/handstand prerequisite","Wrist/shoulder pain","Poor landing control","No qualified coach for beginners"]}'::jsonb,
