  coaching_execution = '{"movement_description":"Mini hurdle or skip into balanced lunge freeze, arms by ears.","setup":["Start standing tall.","Arms by ears or in controlled swing pattern.","Use floor markers if needed.","Choose lead leg."],"execution_steps":["Step or mini-skip into hurdle.","Land in lunge.","Front foot under knee.","Back leg controlled.","Arms by ears.","Freeze balance."],"coach_cues":["Small hurdle.","Land balanced.","Chest tall.","Front foot under knee.","Do not dive forward."],"athlete_cues":["Skip to lunge.","Freeze.","Arms up.","Stay tall."],"common_faults":["Over-leaning forward.","Front foot reaching too far.","Back leg lifting too early.","Arms dropping.","Landing off-balance.","Rushing into cartwheel/round-off before lunge is stable."],"stop_signs":["Knee pain.","Ankle instability.","Repeated loss of balance.","Athlete cannot freeze the entry."]}'::jsonb,
