UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('log-roll', 'Excellent for youth beginners. For adults, reduce reps if vestibular tolerance is low.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('egg-roll', 'Strong youth beginner drill. For larger or older athletes, use thicker mats and lower volume.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('rock-and-roll-to-stand', 'Youth athletes often learn this quickly. Adults may need wedge support and more hip/ankle mobility.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('forward-roll-progression', 'Children often learn on wedge mats; adults need more neck-safety education and regressions.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('backward-roll-progression', 'Use mats, simple language, short sets, and clear shape goals.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('shoulder-roll-progression', 'Useful for ninja/parkour contexts with clear safety coaching and low-risk surface.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('donkey-kick', 'Excellent for children. Adults may need more wrist/shoulder prep and elevated-hand regressions.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('wall-walk-handstand-line', 'Youth need clear stop points and supervision. Adults often require wrist/shoulder prep and fear management.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('handstand-kick-up-wall', 'Young athletes require supervision and simple language. Adults need more fear management and safe-exit education.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('cartwheel', 'Great for youth. Adults may need elevated hand support and slower leg turnover.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('cartwheel-step-over', 'Very useful for youth beginners. Adults may need elevated hands or lower obstacle first.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
  ('cartwheel-finish-lunge', 'Useful for all ages. Children respond well to freeze-count games.', 'No default male/female dosage split. Scale by training age, body size, mobility, upper-body support tolerance, fear, symptoms, and prerequisites.'),
