-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('log-roll', 'The log roll teaches the athlete to maintain a long body shape while rotating around the body''s long axis. It builds body tension, left/right orientation, vestibular tolerance, and organized limbs during rotation — one of the safest first rolling drills because it avoids neck loading and inversion.', 'Belongs in rolling_foundation (221) — first orientation rolling drill before compact tuck rolls and forward/backward progressions.', 'First rolling drill in Rotation / Inversion / Tumbling Foundations before tuck rolls, hollow-to-arch rolls, or forward rolls.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Log rolls are spatial-orientation and body-tension drills, not conditioning. Avoid dizzying high rep volume.', 'Scale by vestibular tolerance and mat spacing; regress to half rolls or arms at sides.'),
  ('egg-roll', 'The egg roll teaches compact organization needed in tuck rolls and early forward/backward roll progressions, with lower risk than a full forward or backward roll.', 'Belongs in rolling_foundation — compact rolling after log roll, before roll-to-stand transitions.', 'After tuck shape awareness and before forward roll or rock-and-roll to stand.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Do not progress to forward roll if athlete cannot keep compact shape.', 'Scale by knee flexion tolerance and vestibular response; use seated tuck hold regressions.'),
  ('rock-and-roll-to-stand', 'Teaches momentum management, compact shape, and balanced stand-up — bridging tuck rocks to forward/backward roll progressions.', 'Belongs in roll_to_stand (222) — bridge between tuck rocks and full roll progressions.', 'Before forward rolls, backward roll progressions, and stand-up transitions.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Do not allow neck contact or excessive rep volume before stand-up is controlled.', 'Regress to tuck rock only or wedge-assisted rock; scale hip and ankle mobility for adults.'),
  ('forward-roll-progression', 'Fundamental tumbling skill teaching safe forward rotation, compact shape, spatial orientation, and stand-up control with chin tuck and hand support on mat.', 'Belongs in forward_roll (223) — first full forward rotation after rolling foundations.', 'After tuck, rock, and neck-safety cues are established. Mat and supervision required.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Neck safety and chin tuck are non-negotiable. Do not use dive rolls in beginner Skill phase.', 'Regress to rock-and-roll, wedge roll, or seated tuck finish; adults need extra neck-safety education.'),
  ('backward-roll-progression', 'Teaches backward rotation with hands near shoulders/ears and arm push to clear the neck. Progression uses pizza hands, rock-and-roll, incline, panel mat, and spotting.', 'Belongs in backward_roll (224) — gated progression after forward roll readiness.', 'After tuck rocks, forward rolls, and hand-placement prep. Beginners need wedge/panel mat or spotting.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Correct hand placement and arm push are essential. End attempts immediately on neck loading.', 'Use pizza-hand rocker, flapjack, incline, panel mat, or coach spot before independent rolls.'),
  ('shoulder-roll-progression', 'Shoulder roll disperses impact diagonally rather than stopping abruptly — a real-world fall-skill progression from hand placement to standing rolls.', 'Belongs in shoulder_roll (225) — safety roll before hard-surface or high-speed obstacle work.', 'As safety and orientation drill for ninja, parkour-style movement, obstacle training, and fall-prep.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Never teach on hard surfaces before mat mastery.', 'Start kneeling or seated diagonal rock; wedge-assisted progressions for beginners.'),
  ('donkey-kick', 'Teaches pressure through straight arms, finger pressure, leg drive, and posture for handstand entry without high-volume conditioning.', 'Belongs in hand_support_inversion (226) — bridge to handstand and cartwheel weight transfer.', 'Bridge between front support and inversion. Keep hops small and technical.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. High-volume bunny hops become conditioning or wrist/shoulder fatigue — cap at ~10 reps per block.', 'Regress to bear crawl shifts, floor hip lifts, or elevated hands on panel mat.'),
  ('wall-walk-handstand-line', 'Develops inversion confidence, shoulder elevation, hand pressure, body-line awareness, and handstand-specific trunk control with wall support.', 'Belongs in handstand_line (227) — line drill before kick-up entry work.', 'After wrist, shoulder, front support, and bunny-hop preparation. Technical and short — not endurance.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Long holds shift to Control / Resilience. Cap holds at ~20s in Skill phase.', 'Regress to down-dog L-shape, box pike hold, or lower feet on wall.'),
  ('handstand-kick-up-wall', 'Coordinates hand placement, shoulder stack, lunge, kick leg, push leg, trunk control, and exit awareness — a skill, not just strength.', 'Belongs in handstand_entry (228) — controlled entry after line drill readiness.', 'After front support, bunny hop, wall line, and safe exit education.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Overkicking into wall or long holds belong in Output or Control, not Skill.', 'Regress to wall body-line, box pike, donkey kick, or assisted scissor lift.'),
  ('cartwheel', 'Cartwheels depend on weight transfer, line awareness, and hand-hand-foot-foot rhythm. Line drills build alignment before full turnover.', 'Belongs in cartwheel_foundation (229) — hand placement before step-over progressions.', 'Before full cartwheels or cartwheel-over-mat progressions. Goal is clean hand-foot rhythm, not speed.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Do not rush full cartwheel if hand order or line awareness is inconsistent.', 'Regress to hand placement only, side donkey kick over line, or raised panel mat hands.'),
  ('cartwheel-step-over', 'Panel mat or low obstacle gives a visual target and organizes hand-hand-foot-foot rhythm toward higher cartwheels.', 'Belongs in cartwheel_foundation (229) — step-over after line hand-placement drill.', 'After hand-placement line drill. Obstacle gives a target and improves confidence.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Obstacle height should create success, not fear or excessive power.', 'Lower obstacle, hand placement only, or coach spot at hips.'),
  ('cartwheel-finish-lunge', 'Many athletes focus on getting over and forget the finish. Freeze drills build lunge posture, arms by ears, and direction control.', 'Belongs in cartwheel_finish (230) — finish control before round-off entry.', 'When athletes can get over but lose posture, direction, or balance at the end of the cartwheel.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Finish-position drill; not a full tumbling endurance drill.', 'Static lunge freeze, step to lunge from line, or baby cartwheel to lunge.'),
  ('round-off', 'Round-off lands with two feet together and sets up rebound/backward tumbling. Snap-down teaches hollow shape, heel drive, and shoulder push.', 'Belongs in roundoff_foundation (231) — technical snap-down before Output power work.', 'Only after cartwheel, handstand line, and basic snap-down prerequisites. Technical — not max power.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Skill-phase version is technical snap-down, not a max-power round-off.', 'Hollow snap-down on floor, wall handstand snap-down, cartwheel to feet-together finish.'),
  ('hurdle-step-lunge', 'The hurdle sets balance and weight transfer before tumbling skills. Upright posture and stacked lunge prevent over-leaning and loss of force direction.', 'Belongs in hurdle_entry (232) — entry rhythm before cartwheel or round-off step-in.', 'Before cartwheel step-in, round-off entry, or tumbling passes. Balance and weight transfer — not speed.', 'Tumbling foundations should happen while the athlete is fresh enough to think, react, organize, and stay safe. Do not become high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance work, or conditioning with gymnastics skills. Fast/power hurdle belongs closer to Output. Skill phase is posture, balance, and entry shape.', 'Step to lunge freeze, march to lunge, or band-assisted weight-shift before skip/hurdle rhythm.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Tumbling-cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'skill_tumbling_readiness',
  NULL,
  'Rotation / Tumbling Foundations without pre-fatigue',
  'Rolling, inversion, and tumbling prerequisite drills should sharpen orientation, shape, and safe contact while athletes are fresh — not become conditioning, max-power tumbling, or handstand endurance work.',
  'Tumbling foundation cards teach rolling, hand support, inversion tolerance, cartwheel rhythm, round-off snap-down shape, and hurdle entry while athletes can think, react, and stay safe.',
  'Fatigue rolling, neck-unsafe progressions, and high-volume hand support before skill work increase injury risk and poor mechanics that transfer into Output tumbling.',
  'Require mats for rolls, gate forward/backward rolls behind tuck and rock progressions, cap handstand holds at ~20s in Skill, keep donkey kicks ≤10 reps per block, sequence cartwheel line before step-over and round-off, and stop rotational work on dizziness or neck symptoms.',
  'Do not assign high-volume tumbling, fatigue rolling, max-power round-offs, handstand endurance holds, or gymnastics skills as conditioning in Skill — reduce dose or change phase intent.'
)
